import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { PRODUCT_CATEGORIES } from "../constants/constants";
import { FaStar } from "react-icons/fa"; // ⭐ Modern icon-based rating
import { getPriceQueryParams } from "../../utils/getPriceQueryParams";

const Filters = () => {
  const [min, setMin] = useState(0);
  const [max, setMax] = useState(0);
  const navigate = useNavigate();
  let [searchParams] = useSearchParams();

  useEffect(() => {
    if (searchParams.has("min")) setMin(searchParams.get("min"));
    if (searchParams.has("max")) setMax(searchParams.get("max"));
  }, []);

  // Handle Category & Ratings filter
  const handleClick = (checkbox) => {
    const checkboxes = document.getElementsByName(checkbox.name);
    checkboxes.forEach((item) => {
      if (item !== checkbox) item.checked = false;
    });

    if (!checkbox.checked) {
      searchParams.delete(checkbox.name);
    } else {
      searchParams.set(checkbox.name, checkbox.value);
    }

    const path = `${window.location.pathname}?${searchParams.toString()}`;
    navigate(path);
  };

  // Handle price filter
   const handleButtonClick = (e) => {
    e.preventDefault();

    searchParams = getPriceQueryParams(searchParams, "min", min);
    searchParams = getPriceQueryParams(searchParams, "max", max);

    const path = window.location.pathname + "?" + searchParams.toString();
    navigate(path);
  };

  const defaultCheckHandler = (checkboxType, checkboxValue) =>
    searchParams.get(checkboxType) === checkboxValue;

  // ⭐ Custom simple star display
  const StarRating = ({ rating }) => {
    return (
      <div style={{ display: "flex", gap: "2px", alignItems: "center" }}>
        {[1, 2, 3, 4, 5].map((i) => (
          <FaStar
            key={i}
            size={20}
            color={i <= rating ? "#ffb829" : "#e4e5e9"}
          />
        ))}
      </div>
    );
  };

  return (
    <div className="border p-3 filter">
      <h3>Filters</h3>
      <hr />
      <h5 className="filter-heading mb-3">Price</h5>
      <form id="filter_form" className="px-2" onSubmit={handleButtonClick}>
        <div className="row g-2">
          <div className="col">
            <input
              type="text"
              className="form-control"
              placeholder="Min ($)"
              name="min"
              value={min}
              onChange={(e) => setMin(e.target.value)}
            />
          </div>
          <div className="col">
            <input
              type="text"
              className="form-control"
              placeholder="Max ($)"
              name="max"
              value={max}
              onChange={(e) => setMax(e.target.value)}
            />
          </div>
          <div className="col-auto">
            <button type="submit" className="btn btn-primary w-100">
              GO
            </button>
          </div>
        </div>
      </form>

      <hr />
      <h5 className="mb-3">Category</h5>
      {PRODUCT_CATEGORIES?.map((category, index) => (
        <div className="form-check" key={index}>
          <input
            className="form-check-input"
            type="checkbox"
            name="category"
            id={`category-${index}`}
            value={category}
            defaultChecked={defaultCheckHandler("category", category)}
            onClick={(e) => handleClick(e.target)}
          />
          <label
            className="form-check-label"
            htmlFor={`category-${index}`}
            style={{ cursor: "pointer" }}
          >
            {category}
          </label>
        </div>
      ))}

      <hr />
      <h5 className="mb-3">Ratings</h5>
      {[5, 4, 3, 2, 1].map((rating, index) => (
        <div className="form-check d-flex align-items-center" key={index}>
          <input
            className="form-check-input me-2"
            type="checkbox"
            name="ratings"
            id={`rating-${rating}`}
            value={rating}
            defaultChecked={defaultCheckHandler("ratings", rating.toString())}
            onClick={(e) => handleClick(e.target)}
          />
          <label
            className="form-check-label"
            htmlFor={`rating-${rating}`}
            style={{ cursor: "pointer" }}
          >
            <StarRating rating={rating} />
          </label>
        </div>
      ))}
    </div>
  );
};

export default Filters;
